INSERT INTO books (id, tenant_id, title, author, description, price, stock, category_id, is_active) VALUES
  ('00e30fd7-45d6-59b1-b654-9200b466a559', 'a0000000-0000-0000-0000-000000000001', 'Алтан ганжуур', 'Зохиогч', 'Энэ ба хойт насны буян хураахуйн тухайд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 20000.00, 100, '7dd358f3-2adf-505c-8788-a197530839d3', true),
  ('0b9fbebd-fb3e-5ff8-af0f-7b110fd3bfa8', 'a0000000-0000-0000-0000-000000000001', 'Банзрагчийн таван сахьяа', 'Зохиогч', '''Банзрагчийн таван сахьяа'' нь эд хөрөнгө арвижуулах, өрх гэрийн санхүүгийн бат бэх байдал, аз хийморийг дэмжихэд зориулагдсан.', 1500.00, 100, '6b9c359d-f498-5a02-952f-b7d015c895e5', true),
  ('dd7263b7-7c8f-5839-9dc1-573c60725a57', 'a0000000-0000-0000-0000-000000000001', 'Гүнсэн түгийн мандал', 'Зохиогч', 'Бурхны лагшин, зарлиг, таалалд бие, хэл, сэтгэлийн буянаа мандал болгон өргөж сайн сайхныг бурханд даатгадаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, '1343141f-4282-5918-8b19-937069fb7d19', true),
  ('5baf5515-0cc7-5d4c-a07d-fe3c405af3e0', 'a0000000-0000-0000-0000-000000000001', 'Алтангэрэл', 'Зохиогч', 'Хувь хүн, өрх гэрийн эд хөрөнгө, буян хишгийг арвижуулахад болон аливаа гарз, гал усны аюул, гай зэтгэр, өвчин зовлон зэргээс гэтэлгэхийн тухайд айлтгуулна. Насны буян арвитгах, барцад саад арилгах. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, 'e8c30adb-db5b-531b-ae22-f476ac72c8ae', true),
  ('ad468a64-09ac-55ed-9356-f91baf466b5f', 'a0000000-0000-0000-0000-000000000001', 'Алтангэрэлийн даллага', 'Зохиогч', 'Эд эдлэл, идээ ундаа, олз омог, буян хишиг арвижуулан гарзын үүдийг хаахад уншуулна. (Бэлдэж ирэх зүйл: өөрийн дуртай зүйлсээр тавгийн идээ бэлдэж ирэх Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, '9679f529-c98d-5e92-abda-c9da8e3c8c2b', true),
  ('52bd28fd-43d5-55c9-8b5f-7e696d400d68', 'a0000000-0000-0000-0000-000000000001', 'Арван гурван сан', 'Зохиогч', 'Хийморь сэргээж, ажил үйлс бүтээх Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, '099c216f-0af1-5d47-9697-5699447cf881', true),
  ('48510b80-3fd1-516a-9e8d-a7d3e493eb91', 'a0000000-0000-0000-0000-000000000001', 'Аян замын ерөөл', 'Зохиогч', 'Аян замдаа саад барцадгүй явах Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, '86bb1d08-e723-5ded-aa21-f667f6c70bcd', true),
  ('b667b991-0a1e-5c84-adeb-b886b4876a11', 'a0000000-0000-0000-0000-000000000001', 'Арван хангал', 'Зохиогч', 'Сахиусанд даатгаж, саад барцадгүй амар мэнд байх. /Идээтэй/ Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 25000.00, 100, NULL, true),
  ('4c2737c7-3b54-5375-8e73-fd8f91ef39ad', 'a0000000-0000-0000-0000-000000000001', 'Бадам хатан', 'Зохиогч', 'Ажил үйлс бүтээх, гай барцад, хорлолгүй амар амгалан байлгахын тухайтад Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('917254db-f04a-59c7-b1d1-cbade3e3cfb4', 'a0000000-0000-0000-0000-000000000001', 'Базарсад', 'Зохиогч', 'Нүгэл хилэнц арилгах, лай ланчиг нимгэлэх Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, NULL, true),
  ('7db001d5-801f-5775-8798-c01695039873', 'a0000000-0000-0000-0000-000000000001', 'Банзрагч', 'Зохиогч', 'Хилэнц арилгах Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
