  ('ecd70264-aeb8-504b-b329-e7e0d1f3c894', 'a0000000-0000-0000-0000-000000000001', 'Юл лха сэржим', 'Зохиогч', '''Юл лха сэржим'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('7e796d94-6fe8-599c-b567-b41edc190be5', 'a0000000-0000-0000-0000-000000000001', 'Жадамба', 'Зохиогч', 'Үйлс бүтээх, бузар арилгахад тустай заслын ном. Энэ ба хойт насны буянд, санасан бүх үйлс бүтээх, буян дэлгэрүүлэх, ухаан сайжруулах, муу бүхнийг зайлуулах, аюул ослоос хамгаалахад айлдуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('78e3e518-260a-5130-b996-ed06f90a0d4e', 'a0000000-0000-0000-0000-000000000001', 'Дүншаг', 'Зохиогч', 'Энэ хойтын гурван үүд бие, хэл, сэтгэлээр үйлдсэн хилэнц нүглийг наминчлах мөргөлийн ном. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('2a10ec76-00b2-5004-88dc-f9d7d43f34a6', 'a0000000-0000-0000-0000-000000000001', 'Жамбалнагва', 'Зохиогч', 'Гэр байшин, сүм дуганы газар авах, овоо хангай тахих засал, өтгөсийг нутаглуулах, жил, сар, өдрийн бүх засалд айлтгана. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('e7022f8c-ad3d-5535-8f0d-4f8b99f26078', 'a0000000-0000-0000-0000-000000000001', 'Жамбал цанжод', 'Зохиогч', '''Жамбал цанжод'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('985ed846-8b51-5302-a527-b98aa1010b99', 'a0000000-0000-0000-0000-000000000001', 'Жанаггагдог', 'Зохиогч', 'Гай гамшиг, хэрүүл тэмцэл, хорлол хариулах, харш жилийн засал, мэнгэ суудал засуулахад, харшилдах шалтгаан бүхнийг дарахын тухайд уншуулна. Гаригийн заслын гол ном юм. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('64507b35-80cc-5e29-aa21-90391b0e6504', 'a0000000-0000-0000-0000-000000000001', 'Жанлавцогзол', 'Зохиогч', 'Гадна, дотны хямрал тэмцлийг дарахад айлтгуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('6d78c07b-6add-5eb8-8c3a-822b3685b9b1', 'a0000000-0000-0000-0000-000000000001', 'Жанцан зимой бүнжин', 'Зохиогч', 'Ажил үйлс бүтээх, хийморь сэргээх, маргаан таслах Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('b69aa5e9-c167-58b1-993f-4c1608fb5777', 'a0000000-0000-0000-0000-000000000001', 'Жойвын чойжад', 'Зохиогч', '''Жойвын чойжад'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('6b32fad1-3570-5d0a-826f-8f4b25618698', 'a0000000-0000-0000-0000-000000000001', 'Жамсран', 'Зохиогч', 'Улаан сахиус нь ад зэтгэр, гарз гарлага, хэл ам, хэрүүл зарга, хулгай дээрэм, элдэв хорлол хөнөөл зэргийг номхотгон дарагч гол сахиус. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 6000.00, 100, NULL, true),
  ('c0c15552-bf42-5b42-b927-37d9d070328f', 'a0000000-0000-0000-0000-000000000001', 'Жамсран сан', 'Зохиогч', 'Дайсныг номхотгон аюул ослоос хамгаалах, хулгай дээрмээс сэргийлэх, ажил үйлсийг бүтээхийн тухайд өргүүлнэ. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('22c69384-f79e-5d2d-a6c9-9727c435e7b8', 'a0000000-0000-0000-0000-000000000001', 'Жамсран сэржим', 'Зохиогч', 'Аюул ослоос хамгаална. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
