  ('bafad570-c00f-5d34-9efb-eecd06f4b5ec', 'a0000000-0000-0000-0000-000000000001', 'Жамсран доромбүл', 'Зохиогч', '''Жамсран доромбүл'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('0a1f3237-0377-582d-a91d-2c485a29e469', 'a0000000-0000-0000-0000-000000000001', 'Жамсран ганшиг', 'Зохиогч', '''Жамсран ганшиг'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('750db89e-e849-5b92-96bb-be852b0515f7', 'a0000000-0000-0000-0000-000000000001', 'Жамсран сан сэржим мандал', 'Зохиогч', 'Дайсныг номхотгон аюул ослоос хамгаалах, хулгай дээрмээс сэргийлэх, ажил үйлсийг бүтээхийн тухайд өргүүлнэ. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 4500.00, 100, NULL, true),
