  ('ccb850bf-854d-5020-8da5-89be5b50fa2b', 'a0000000-0000-0000-0000-000000000001', 'Жонвий чойжид', 'Зохиогч', '''Жонвий чойжид'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('e3d324ff-ebc6-5b97-bafc-f4b07b16db26', 'a0000000-0000-0000-0000-000000000001', 'Жүгдэр', 'Зохиогч', '''Жүгдэр'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('f0ab8e67-4fb9-551f-8365-f13eee10180a', 'a0000000-0000-0000-0000-000000000001', 'Жүгдэр гарнаг', 'Зохиогч', 'Хар цагаан хэл ам арилгах Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('66f60cb3-45b7-555a-91e9-17c1e5e81252', 'a0000000-0000-0000-0000-000000000001', 'Жүгдэр новог', 'Зохиогч', '''Жүгдэр новог'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('7e14b663-ad5d-5207-a578-0b6c40a81fd3', 'a0000000-0000-0000-0000-000000000001', 'Жүгдэр намжил', 'Зохиогч', '''Жүгдэр намжил'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('4db2479b-ea36-5a79-b08c-c0bc2a076e72', 'a0000000-0000-0000-0000-000000000001', 'Жигжид', 'Зохиогч', 'Есөн нигуур, 16 бойв, 34 мутартай хамгийн догшин ядам ямандаг нь бүх ядам, сахиус, лус, савдаг бүгдийг захирах чадалтай шарын шашны их ядам юм. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 5000.00, 100, NULL, true),
  ('6282e321-3d9b-57dd-826d-d779175159ef', 'a0000000-0000-0000-0000-000000000001', 'Загдзүсэм', 'Зохиогч', 'Хүүхэд, нялхсын өвчин, ад зэтгэр, айх хөлсөхөд айлддаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('412ecf89-0fbe-5475-8c74-c727b5298aa8', 'a0000000-0000-0000-0000-000000000001', 'Заслын найман ном', 'Зохиогч', 'Дашзэвэг ном нь сүм хийд, орон байрны шав тавих, шинэ гэр сууцанд орох, найр наадам хийх, өлзий хутаг оршоох заслын ном. Мөн жил, cap, өдрийн цээрийг арилгах, хорлол хөнөөлд үл өртүүлэх тэргүүтэн тус эрдэм нэн их байдаг. Түүнчлэн айл гэрийн ноён нурууг тэгшитгэх, санасан хэрэг бүгдийг саадгүй бүтээхийн тухайд айлдуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true)
