  ('9b4bff77-5643-5073-8332-1748f5f83ee4', 'a0000000-0000-0000-0000-000000000001', 'Заслын найман ном 3 удаа', 'Зохиогч', 'Жил сар өдрийн засал Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 6000.00, 100, NULL, true),
  ('a6ac90a1-a3a5-5987-b73a-31a17a377596', 'a0000000-0000-0000-0000-000000000001', 'Зүгдор гарнаг', 'Зохиогч', 'Хар цагаан хэл ам арилгах, хамгаалах, Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('2e20026a-d75c-5b37-8aa7-2f6c257df419', 'a0000000-0000-0000-0000-000000000001', 'Зүгдэр намжил', 'Зохиогч', 'Мянган мөргөл, мянган эргэл, мянган тахил өргөж уншдаг хурал. Жүгдэрнамжил бурханд тахил өргөж даатгаснаар өвчин зовлонгоос гэтэлгэн, хойт төрөлд зуурдын зовлон эдлэлгүй диваажинд төрөх ерөөл тавимой. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('7a1318c8-86d0-5ce1-bbd3-974af7e849e9', 'a0000000-0000-0000-0000-000000000001', 'Зургаан ерөөл', 'Зохиогч', 'Бүх сайн сайхныг даатган ерөөл тавихын тухайд уншуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 6000.00, 100, NULL, true),
  ('41ec8f84-c048-5886-9f5b-bc906055feb7', 'a0000000-0000-0000-0000-000000000001', 'Ча сүм', 'Зохиогч', 'Газар лус, нян, бирд, тотгор, савдгийн гүйдэл хаах болон номхотгох, өвчин зовлон, зовлон шаналал, барцад арилгадаг Бурхан багшийн гүрэм. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('4fbdaa75-fa03-5111-9ca0-ed724ab42ab6', 'a0000000-0000-0000-0000-000000000001', 'Чогжү мүнсэл', 'Зохиогч', 'Зүгийн сайн муугийн гэмийг арилгаж аян замд өлзийтэй сайн явах, зорьсон хэргийг саадгүй бүтээхийн тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
