  ('05bc6bc7-d230-5b2e-a92b-e9e685c34b51', 'a0000000-0000-0000-0000-000000000001', 'Чойжилдүгжов', 'Зохиогч', '''Чойжилдүгжов'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 30000.00, 100, NULL, true),
  ('d64cd068-7e0a-503c-9ad3-e834055311b5', 'a0000000-0000-0000-0000-000000000001', 'Цагаан дарь эх', 'Зохиогч', 'Цаг бусын үхлийг арилгаж нас буяныг арвижуулахад айлтгуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('7990352f-ac1b-5c23-96f0-66e5aaa669ec', 'a0000000-0000-0000-0000-000000000001', 'Цагаан дарь эх мянга', 'Зохиогч', 'Насны барцад арилгах өвчин зовлонгүй байхуйд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, NULL, true),
  ('a562c912-f17a-5446-a8b5-4ec45df6aac4', 'a0000000-0000-0000-0000-000000000001', 'Цагаан дарь эх сан сэржим', 'Зохиогч', 'Насны цөв арилгахын тухайд архаг, хүнд өвчтэй хүмүүст мөн эрүүл хүн нас буян хураахын тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2500.00, 100, NULL, true),
  ('c38945d9-84a1-557b-be2c-c5a4b79f6d46', 'a0000000-0000-0000-0000-000000000001', 'Цагаан дарь эх сан', 'Зохиогч', '''Цагаан дарь эх сан'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('16c55059-d17d-5479-a0bf-f71c3d25112a', 'a0000000-0000-0000-0000-000000000001', 'Цагаан шүхэрт', 'Зохиогч', 'Цагаан хэл ам, ном буяны үйлд зориход, өвчин зовлон, саад зэтгэргүй байх, ажил үйлс өөдлөн дэвжихийн тухайд айлтгана. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('a7867392-5114-5cb0-a187-aae571789468', 'a0000000-0000-0000-0000-000000000001', 'Цагаан шүхэрт мянга', 'Зохиогч', 'Цагаан хэл ам буцаах, ган зуд, өвчин эмгэгт Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3500.00, 100, NULL, true),
  ('54dfb7fd-8dc8-50dc-abfe-cd707810c895', 'a0000000-0000-0000-0000-000000000001', 'Цагаан шүхэртийн догжир', 'Зохиогч', 'Хар цагаан хэл ам таслан өвчин зовлонг арилгаж амар амгалан байх тухайд айлдуулдаг гүрэм. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 30000.00, 100, NULL, true),
  ('82975955-d5bd-5759-83df-cf0ed0198c2e', 'a0000000-0000-0000-0000-000000000001', 'Цагаан итгэл', 'Зохиогч', '''Цагаан итгэл'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('a3217b40-c254-51ab-a81c-01034fefce24', 'a0000000-0000-0000-0000-000000000001', 'Цагаан өвгөн сан', 'Зохиогч', 'Газар орноо тахих, хулгай хайх, малын өвчинд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('ed89abca-a168-5dbb-99f2-d6fe329b005e', 'a0000000-0000-0000-0000-000000000001', 'Цагаан өвгөн сэржим', 'Зохиогч', 'Малын хишиг тогтоох болон сүү тараг цагаан идээ арвижуулахын тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('a09038b1-25bf-5236-a427-0c7976aad492', 'a0000000-0000-0000-0000-000000000001', 'Цагаан өвгөн сан сэржим', 'Зохиогч', 'Малын үрс, хишиг тогтоох болон сүү тараг, цагаан идээ арвижуулахад. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2500.00, 100, NULL, true),
  ('509635f7-7572-5300-a7b5-be292a8389bb', 'a0000000-0000-0000-0000-000000000001', 'Цагаан дарь эх сэржим', 'Зохиогч', '''Цагаан дарь эх сэржим'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('4132d55a-f249-58ed-8064-bab3635bdd55', 'a0000000-0000-0000-0000-000000000001', 'Цамба', 'Зохиогч', 'Эсүрэн тэнгэр нь тэрсүүд муу үзлийг номхотгон дарагч Өндөр гэгээний хамгийн ойрын шажныг тэтгэгч сахиус байжээ. Ихэвчлэн муу үзэлтний хараал буцаах, хатуу үйлд сайн. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 5000.00, 100, NULL, true),
  ('54a38f5d-d83c-534a-8e26-7d8870eff2a5', 'a0000000-0000-0000-0000-000000000001', 'Цанжид', 'Зохиогч', '''Цанжид'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('ec493e0a-9059-5789-8ee9-4ea91b9c07c2', 'a0000000-0000-0000-0000-000000000001', 'Цэвээн', 'Зохиогч', '''Цэвээн'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('1e89bf1e-50f8-5084-a483-ace81d178cbe', 'a0000000-0000-0000-0000-000000000001', 'Цэнд', 'Зохиогч', 'Нас уртасгах, насны цөв арилгах, цаг бусын үхлээс гэтэлгэх тухайд айлдуулдаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('cfc45b79-2ba5-5a72-8cd3-9ac81eb57f32', 'a0000000-0000-0000-0000-000000000001', 'Цэнд мянга', 'Зохиогч', 'Нас уртасгах, насны цөв арилгах, цаг бусын үхлээс гэтэлгэхийн тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 4500.00, 100, NULL, true),
  ('3ba73532-dfad-5bf5-92f0-221bfc4bc5d4', 'a0000000-0000-0000-0000-000000000001', 'Цэнд аюуш', 'Зохиогч', '''Цэнд аюуш'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 2000.00, 100, NULL, true),
  ('b1a72e2a-26e3-5461-85ca-15480a7b1f78', 'a0000000-0000-0000-0000-000000000001', 'Цэнгэг сан', 'Зохиогч', '''Цэнгэг сан'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('716e20ed-d3b0-5247-be83-34863dca2517', 'a0000000-0000-0000-0000-000000000001', 'Цонхоо сан', 'Зохиогч', '''Цонхоо сан'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('07885db1-b6f3-52fb-8992-8ab5c60214f5', 'a0000000-0000-0000-0000-000000000001', 'Шавдаг дором', 'Зохиогч', 'Лус савдаг, газар лус баясгахад айлдуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('ef7351fb-011c-5449-9897-dafc7f7b8d6a', 'a0000000-0000-0000-0000-000000000001', 'Шамбалын ерөөл', 'Зохиогч', 'Шамбалын оронд төрөх болон төрүүлэх тухайд. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('9ec2e7ed-dc25-502f-bfbe-1764bb413bb9', 'a0000000-0000-0000-0000-000000000001', 'Шашин нямбуу нанжид', 'Зохиогч', '''Шашин нямбуу нанжид'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('88024ca2-37fd-5369-9878-735e001e4c92', 'a0000000-0000-0000-0000-000000000001', 'Шэйрав нинбо', 'Зохиогч', '''Шэйрав нинбо'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('87563628-a9d6-5dad-9ffd-564dbf363e94', 'a0000000-0000-0000-0000-000000000001', 'Ширнэн', 'Зохиогч', 'Шулмасны хорлолыг буцаах, гай барцадгүй байлгах, сайн зүйл хийхэд учрах саад бүхнийг зайлуулахын тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('3589efac-92a2-5774-91de-97cb391d56f1', 'a0000000-0000-0000-0000-000000000001', 'Шүхэрт', 'Зохиогч', '''Шүхэрт'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('052fa819-f061-5a27-a2de-96bc9be2f553', 'a0000000-0000-0000-0000-000000000001', 'Итгэл', 'Зохиогч', 'Лам гурван эрдэнэд энэ болон хойт насыг даатгах тухайд. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('07d63a80-2b00-5014-88da-be0a277593e9', 'a0000000-0000-0000-0000-000000000001', 'Их манал', 'Зохиогч', 'Энэ төрөлд өвчин зовлонгүй амар амгалан байх, хойт төрөлд зуурдын зовлон эдлэлгүй муу заяаны зовлонгоос гэтлэж сайн төрөлд төрүүлэхэд зориулан айлтгадаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 4000.00, 100, NULL, true),
  ('b0c7ccc1-724e-501e-9904-ca7fb61f2977', 'a0000000-0000-0000-0000-000000000001', 'Саа юм', 'Зохиогч', 'Гаригийн цээрийг арилгах заслын ном. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('687e34e0-ae46-5088-8e04-cd79e2357bb5', 'a0000000-0000-0000-0000-000000000001', 'Саеэ нинбу', 'Зохиогч', 'Суудлын засал, ялангуяа шороонд суух болон лус савдаг нянгийн хорлол зэрэг засалд айлтгадаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('40e9acb1-bef0-53d6-8dec-8905c654216c', 'a0000000-0000-0000-0000-000000000001', 'Самбалхүндэв', 'Зохиогч', 'Санасан хэргийг ажил хэрэг сэтгэлчлэн бүтээхэд айлтгана. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
