  ('4f466ea1-e3e2-5943-8d24-80f0ef71904d', 'a0000000-0000-0000-0000-000000000001', 'Савдаг чадвар', 'Зохиогч', 'Лус савдаг аргадах / сүү орно/ Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('0d9d24a7-cf5a-55d7-8b59-ec6461968c35', 'a0000000-0000-0000-0000-000000000001', 'Санжаа гүнлай', 'Зохиогч', 'Энэ ба хойт насанд Гандангийн орноо төрөхийн ерөөл тавих болон нас нөхцөгсдийн хойтын буянд айлддаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('9afd4368-f41f-58ba-a65e-2609a0fa92ec', 'a0000000-0000-0000-0000-000000000001', 'Сандуйн жүд', 'Зохиогч', 'Өвчин зовлон, муу заяаны зовлон, осол аваараас хамгаалахад айлдуулдаг. Сандуйн жүд уншиж буй газрын салхин доогуур гарахад л муу заяанд унадаггүй адис жинлавтай тарнийн ёсны дээд ном юм. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('a0217ecc-d62d-5b13-b4bb-f342016d9689', 'a0000000-0000-0000-0000-000000000001', 'Сундуй', 'Зохиогч', 'Айл өрхийн жилийн нуруу, бүх төрлийн засалд айлдуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
