  ('74e77436-44ef-5bee-86f4-6e05c160e314', 'a0000000-0000-0000-0000-000000000001', 'Сэдэд мянга', 'Зохиогч', 'Цагаан хэл ам буцаах, ган зуд, өвчин эмгэгт, ном буяны үйлд зориход, саад зэтгэргүй байх, ажил үйлс өөдлөн дэвжихийн тухайд уншуулна. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, NULL, true),
  ('562bfc6d-2fc7-5004-b03e-70fae305cc34', 'a0000000-0000-0000-0000-000000000001', 'Сэндом', 'Зохиогч', 'Хэл ам, хараал хорлолын гэмээс гэтэлгэнэ. Хатуу үйлд сайн. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('eb2eae43-ac87-5fa1-b9ef-82e4b75a73c6', 'a0000000-0000-0000-0000-000000000001', 'Сэрод', 'Зохиогч', 'Хувь хүн, өрх гэрийн эд хөрөнгө, буян хишгийг арвижуулахад болон аливаа гарз, гал усны аюул, гай зэтгэр, өвчин зовлон зэргээс гэтэлгэхийн тухайд айлтгуулна. Насны буян арвитгах, барцад саад арилгах. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('326b1257-614f-592f-a54c-25493ea5b257', 'a0000000-0000-0000-0000-000000000001', 'Сэмнидпэрэнлай', 'Зохиогч', 'Ад зэтгэрийг амарлиулж, нас буян арвижуулж, эрх мэдэлтэй байлгах, элдэв гай тотгорыг арилган ажил үйл бүтээх зэрэг дөрвөн үйлийг түргэн бүтээхэд Лхам бурханд даатгадаг магтаал. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('d59a3217-dbec-573d-a4a2-6a5406b11a70', 'a0000000-0000-0000-0000-000000000001', 'Сосор барам', 'Зохиогч', 'Өвчин зовлон, ад зэтгэр, элдэв хорлолоос гэтэлгэх тогтоол тарни. Үрийн хишиг буян тогтоох зэрэг хүүхдэд ихэвчлэн уншуулж заншсан байдаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('72ea5b0e-74b6-5cbc-bab2-7ce01fe7eaf5', 'a0000000-0000-0000-0000-000000000001', 'Равнай', 'Зохиогч', '''Равнай'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('d501fa4b-c681-5f07-b917-ab27db151150', 'a0000000-0000-0000-0000-000000000001', 'Хамчунагва', 'Зохиогч', 'Аливаа хэл ам, хэрүүл тэмцэл арилгах, хууль цаазын гэм ослоос хамгаалахад айлдуулдаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('dbdeb347-5fab-517a-812f-d4c7ef0b0e4a', 'a0000000-0000-0000-0000-000000000001', 'Хамчунагва сэржим', 'Зохиогч', 'Хар хэл ам, хэрүүл тэмцэл, хараал жатга, зарга залхайн гай хорлолыг буцаана. Хууль цаазын омтгой ослоос хамгаалах, хэл амнаас зайлуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('7bff759e-299f-5cb9-a0fe-6d0f8ef7168f', 'a0000000-0000-0000-0000-000000000001', 'Хан уулын сан сэржим', 'Зохиогч', '''Хан уулын сан сэржим'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 2500.00, 100, NULL, true),
  ('6f56c507-ed3b-5cdf-a685-96a9bdbd17fa', 'a0000000-0000-0000-0000-000000000001', 'Хан уулын сэржим', 'Зохиогч', '''Хан уулын сэржим'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('358ba129-6654-5d66-aca9-93d690cd2daa', 'a0000000-0000-0000-0000-000000000001', 'Хан уулын сан', 'Зохиогч', '''Хан уулын сан'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('d6ce2955-3ce6-5684-99e8-0c2503259ab6', 'a0000000-0000-0000-0000-000000000001', 'Хамчунавга олноор', 'Зохиогч', 'Хар хэл ам, хэрүүл тэмцэлийн засал Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, NULL, true),
  ('7c8cb10a-b2c6-55a1-b4fb-796f7ac7d155', 'a0000000-0000-0000-0000-000000000001', 'Хамчу гарвуу', 'Зохиогч', '''Хамчу гарвуу'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 2000.00, 100, NULL, true),
  ('0678c924-e7ba-50dc-aca1-b118defa86fc', 'a0000000-0000-0000-0000-000000000001', 'Хийморын сан', 'Зохиогч', 'Ажил үйлс бүтээж, үйлс тэгширч, хийморь лундаа бадарна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('bde473d9-d2f1-504d-a5a3-68aecc56a0fb', 'a0000000-0000-0000-0000-000000000001', 'Хурал даган баясах', 'Зохиогч', 'Хурал даган баяссанаар хуралд таны нэрийг тусгайлан дуудаж бурхан, сахиус шүтээнд даатгадаг болой. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 0.00, 100, NULL, true),
  ('8883ddd7-635d-565b-a00e-c9bc168f419d', 'a0000000-0000-0000-0000-000000000001', 'Хорин нэгэн дарь эх', 'Зохиогч', 'Өвчин эмгэгээс гэтэлгэж, үгүйсгэл хоосролоос аврагч Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('00c4f57e-21f4-545b-85a7-58f6d83cd287', 'a0000000-0000-0000-0000-000000000001', 'Маанийн ерөөл', 'Зохиогч', 'Нас нөгчигсдийн хойтын буянд уншуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('aaf62198-90df-5a03-b3b8-b408dcd6a634', 'a0000000-0000-0000-0000-000000000001', 'Манал', 'Зохиогч', 'Эрүүл энх байлгах, өвчин зовлонгоос гэтэлгэх Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('1eb635f1-e969-53d9-bd80-37d1c996289c', 'a0000000-0000-0000-0000-000000000001', 'Мажин жанлав', 'Зохиогч', '''Мажин жанлав'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('33f9a8c0-a25c-5f79-a80f-79a1b5fd317a', 'a0000000-0000-0000-0000-000000000001', 'Мэвагүнжи жойтов', 'Зохиогч', '''Мэвагүнжи жойтов'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 2000.00, 100, NULL, true),
  ('b32248e6-c107-5ff1-a3e4-6ab046e2251c', 'a0000000-0000-0000-0000-000000000001', 'Миеэ гомбын додба', 'Зохиогч', 'Амар мэнд байх, бие сэтгэл хямрахгүй байхуйд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('a5a41c2c-47f5-54a8-93d5-10281c40162e', 'a0000000-0000-0000-0000-000000000001', 'Миргад намжим', 'Зохиогч', '''Миргад намжим'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('3d584d62-dc74-50e0-8507-e47d98ab5ac4', 'a0000000-0000-0000-0000-000000000001', 'Молом намсүн', 'Зохиогч', 'Нас нөгчигсдийг сайн төрөл түргэн олоход Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('052e2374-0f0f-58cf-beb8-15bc3d253a91', 'a0000000-0000-0000-0000-000000000001', 'Ламаадан', 'Зохиогч', 'Манзуширийн магтаал: Оюун билэг хурцалж, ухаан сайжруулах, эрдэм ном сурахын тухайд уншуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('6552f3b1-11cd-5eac-986c-c43e1bf4db64', 'a0000000-0000-0000-0000-000000000001', 'Ланчигдором', 'Зохиогч', 'Ужиг өвчин, зовлон, лай ланчиг, ад дон амирлуулахын тухайд уншуулна Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('d3d8c21c-793d-50d4-a6b5-a188beaa6715', 'a0000000-0000-0000-0000-000000000001', 'Лаарав лүндэн', 'Зохиогч', '''Лаарав лүндэн'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('afd5ea1a-df92-5290-89f9-97f63df2a5d0', 'a0000000-0000-0000-0000-000000000001', 'Лусын сан', 'Зохиогч', 'Газар лус аргадах, гал усны аюул, лусын гаралтай өвчний хорлол зэргийг арилгахын тухайд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('21432e60-0036-545a-aea2-0f1908c42e2c', 'a0000000-0000-0000-0000-000000000001', 'Лусын сан сэржим', 'Зохиогч', 'Газар лус аргадах, гал усны аюул, лусын гаралтай өвчний хорлол зэргийг арилгахын тухайд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 3000.00, 100, NULL, true),
  ('6b9865b0-fdcd-5b09-b18a-fa1932f085ee', 'a0000000-0000-0000-0000-000000000001', 'Лусын сэржим', 'Зохиогч', 'Газар лус аргадах, гал усны аюул, лусын гаралтай өвчний хорлол зэргийг арилгахын тухайд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('1aa67564-8a4f-531b-ab06-13d5a41da15d', 'a0000000-0000-0000-0000-000000000001', 'Лундаа сан', 'Зохиогч', 'Хийморь, цог золбоо Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('6fe78fbd-b0ad-57e2-8251-5d0659fbd336', 'a0000000-0000-0000-0000-000000000001', 'Лүй вангон', 'Зохиогч', 'Лус савдгийг аргадах, газар гуйх болон эмийн ургамал газраас түүхэд Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
  ('259fac89-8d64-5883-b0f9-fa1665fcadd8', 'a0000000-0000-0000-0000-000000000001', 'Лүйжин', 'Зохиогч', 'Орчлонгийн муу хорт сэтгэлийн үндсийг таслагч. Лүйжин уншуулсан хүн биед шингэсэн бүх муу энерги болон өвчин бүгдийн шалтгаан арилдаг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 20000.00, 100, NULL, true),
  ('a7c246f3-86c5-578c-98b4-fa1f405d70c1', 'a0000000-0000-0000-0000-000000000001', 'Лүй аг ид сүмжиндол', 'Зохиогч', '''Лүй аг ид сүмжиндол'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 1500.00, 100, NULL, true),
  ('c50e0853-f0a0-576f-8095-89cc3070f471', 'a0000000-0000-0000-0000-000000000001', 'Лүмбэнгарав', 'Зохиогч', 'Лусад учирсан өвчин хорлол, лусын хилэн хорлол зэргийг засаж амирлуулах Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 2000.00, 100, NULL, true),
  ('2acb8413-e75f-5350-afa0-49543d144ef9', 'a0000000-0000-0000-0000-000000000001', 'Лүнбүн гарнаг тасун', 'Зохиогч', '''Лүнбүн гарнаг тасун'' нь буян хишиг арвижуулах, сэтгэл санааг ариусган тэтгэхэд уншдаг судар юм.', 4000.00, 100, NULL, true),
