  ('7b475107-fc86-5226-ab82-f1f5011226fa', 'a0000000-0000-0000-0000-000000000001', 'Ловон бадамжунай ламын налжор', 'Зохиогч', 'Номыг уншиж дуурсгаснаар элдвийн гай барцадыг зайлуулна. Айл гэрийн ноён нурууг тэгшитгэх, гэр орныг амгалан байлгахад Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 1500.00, 100, NULL, true),
