  ('99c567a9-40fd-5f1c-a776-3be81f35909d', 'a0000000-0000-0000-0000-000000000001', 'Оройн ерөөл', 'Зохиогч', 'Энэ оройн дээд ерөөлийг хойд насны буянд, амьдын буян үйлдэхэд зориулан уншуулна. Их ерөөл магтаал хурал юм. Бурхан багшийн рид хувилгаан үзүүлсэнд зориулан Өндөр гэгээн Их хүрээнд "Цагаан сарын их ерөөл" нэртэй хуруулж эхэлсэн гэдэг. Энэ ном нь хүмүүсийн өдөр тутмын амьдралд хэрэглэгдэхийн зэрэгцээ сүсэгтэн олонд итгэл урам, ариун сэтгэлийг бэлэглэдэг.', 6000.00, 100, NULL, true),
